# @MEMO 需求：粘入新版本log自动插入CHANGELOG顶部并推送公开库 | 注意：公开库路径~/zhongqu_public

import os, subprocess

PUBLIC    = os.path.expanduser("~/zhongqu_public")
CHANGELOG = os.path.join(PUBLIC, "CHANGELOG.md")
SECTION_KEYS = ["变更", "修复", "优化", "删除", "架构说明", "重构"]

def format_log(lines):
    result = []
    for line in lines:
        s = line.strip()
        if not s: continue
        if s.startswith("v") and ("—" in s or " - " in s or (len(s) > 3 and s[1].isdigit())):
            s = "## " + s if not s.startswith("#") else s
        elif any(s.startswith(k) for k in SECTION_KEYS):
            s = "### " + s.rstrip("：").rstrip(":") if not s.startswith("#") else s
        elif not s.startswith("-") and not s.startswith("#"):
            s = "- " + s
        result.append(s)
    return result

def build_entry(formatted):
    out = []
    for line in formatted:
        if line.startswith("##") and not line.startswith("###"): out.append(line)
        elif line.startswith("###"): out.append("\n" + line)
        else: out.append(line)
    return "\n".join(out).strip()

print("\n=== 发布更新日志 ===")
print("粘入log内容，END结束：\n")

lines = []
while True:
    line = input()
    if line.strip() == "END": break
    lines.append(line)

if not lines:
    print("⚠️ 没有内容")
else:
    formatted  = format_log(lines)
    new_entry  = build_entry(formatted)
    commit_msg = next(
        (l.lstrip("#").strip() for l in formatted if l.startswith("##") and not l.startswith("###")),
        "更新日志"
    )

    old = ""
    if os.path.exists(CHANGELOG):
        with open(CHANGELOG, encoding="utf-8") as f:
            old = f.read()

    if commit_msg and commit_msg in old:
        print(f"⚠️ 版本「{commit_msg}」已存在，跳过")
    else:
        if "# Changelog" in old:
            rest        = old.split("# Changelog", 1)[1].lstrip("\n")
            new_content = f"# Changelog\n\n{new_entry}\n\n---\n\n{rest}"
        else:
            new_content = f"# Changelog\n\n{new_entry}\n\n---\n\n{old}".strip()

        with open(CHANGELOG, "w", encoding="utf-8") as f:
            f.write(new_content)

        print(f"\n写入：{commit_msg}")
        print("\n预览：")
        for l in new_entry.splitlines()[:8]: print(f"  {l}")
        if len(new_entry.splitlines()) > 8: print("  ...")

        if input("\n确认推送？(y/n)：").strip().lower() == "y":
            subprocess.run(["git", "-C", PUBLIC, "add", "CHANGELOG.md"], capture_output=True)
            r2 = subprocess.run(["git", "-C", PUBLIC, "commit", "-m", commit_msg],
                                capture_output=True, text=True)
            if "nothing to commit" in r2.stdout + r2.stderr:
                print("✅ 无新变更")
            elif r2.returncode != 0:
                print(f"❌ commit失败：{r2.stderr[:200]}")
            else:
                r3 = subprocess.run(["git", "-C", PUBLIC, "push"], capture_output=True, text=True)
                print(f"✅ 已推送：{commit_msg}" if r3.returncode == 0 else f"❌ 推送失败：{r3.stderr[:200]}")
        else:
            print("已取消，文件已写入本地")

