# @MEMO 需求：包历史库，查索引/取历史/看当前/快照 | 注意：packs/在_base_dir下

import os, shutil
from datetime import datetime

PACKS_DIR    = os.path.join(_base_dir, "packs")
INDEX_FILE   = os.path.join(PACKS_DIR, "index.md")
CURRENT_FILE = os.path.join(PACKS_DIR, "current.md")

os.makedirs(PACKS_DIR, exist_ok=True)

TAG_RULES = {
    "#架构": ["架构", "中枢", "内核", "结构", "设计"],
    "#协议": ["协议", "指令", "格式", "存档", "规范"],
    "#记忆": ["记忆", "包", "历史层", "动态层", "锚"],
    "#代码": ["代码", "函数", "exec", "python", "bug", "错误"],
    "#决策": ["决策", "删除", "重构", "方案", "确认"],
    "#问题": ["未解决", "偏移", "断裂", "风险"],
}

def auto_tag(text):
    tags = [tag for tag, kws in TAG_RULES.items() if any(k in text for k in kws)]
    return " ".join(tags) if tags else "#其他"

def read_index():
    if not os.path.exists(INDEX_FILE):
        return []
    with open(INDEX_FILE, encoding="utf-8") as f:
        return [l.strip() for l in f if l.strip() and not l.startswith("#")]

def read_pack_file(filename):
    path = os.path.join(PACKS_DIR, filename)
    if not os.path.exists(path):
        return None
    with open(path, encoding="utf-8") as f:
        return f.read()

def extract_summary(text):
    for line in text.splitlines():
        line = line.strip()
        if line.startswith("★项目：") and len(line) > 4:
            return line[4:50]
    for line in text.splitlines():
        line = line.strip()
        if line and not line.startswith(("【", "?", "!", "→")):
            return line[:40]
    return "（无摘要）"

def snapshot_current():
    if not os.path.exists(CURRENT_FILE):
        return None
    content = open(CURRENT_FILE, encoding="utf-8").read()
    ts       = datetime.now().strftime("%Y-%m-%d_%H%M%S")
    filename = ts + ".md"
    shutil.copy2(CURRENT_FILE, os.path.join(PACKS_DIR, filename))
    entry = (datetime.now().strftime("%Y-%m-%d %H:%M") + " | " +
             extract_summary(content) + " | " +
             auto_tag(content) + " | " + filename + "\n")
    with open(INDEX_FILE, "a", encoding="utf-8") as f:
        f.write(entry)
    return filename

print("\n=== 历史库 ===")
print("  1. 快照当前包（存入历史）")
print("  2. 查看索引")
print("  3. 取历史包全文")
print("  4. 看当前包")
c = input("选择：").strip()

if c == "1":
    filename = snapshot_current()
    if filename:
        print(f"\n✅ 快照已存：{filename}")
    else:
        print("⚠️ current.md 不存在")

elif c == "2":
    lines = read_index()
    if not lines:
        print("（索引为空）")
    else:
        print(f"\n共 {len(lines)} 个快照：\n")
        for l in lines:
            print("  " + l)

elif c == "3":
    lines = read_index()
    if not lines:
        print("（无历史快照）")
    else:
        print("\n历史快照列表：")
        for i, l in enumerate(lines, 1):
            print(f"  {i}. {l}")
        nums = input("\n输入编号（逗号分隔）：").strip()
        for n in nums.split(","):
            n = n.strip()
            if not n.isdigit():
                continue
            idx = int(n) - 1
            if 0 <= idx < len(lines):
                parts   = lines[idx].split(" | ")
                content = read_pack_file(parts[-1] if parts else "")
                if content:
                    print(f"\n{'='*40}")
                    print(f"  {lines[idx]}")
                    print(f"{'='*40}")
                    print(content)
                else:
                    print(f"  ⚠️ 文件不存在：{parts[-1]}")

elif c == "4":
    if not os.path.exists(CURRENT_FILE):
        print("（当前包不存在）")
    else:
        with open(CURRENT_FILE, encoding="utf-8") as f:
            print(f.read())

else:
    print("无效选择")

